#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const int &p){if(p>9)print(p/10);putchar(p%10+'0');}
inline void pt(const int &p,const char &ch='\n'){print(p<0?putchar('-'),-p:p);putchar(ch);}
template<typename T> inline void Swap(T &x,T &y){T tmp=x;x=y;y=tmp;}

const int N=1e5+10;int fa[N],s[N][2],xr[N],vl[N];bool tg[N];
struct Splay{int s[2],fa,xr,vl;bool tg;}t[N];int n;
inline bool isSon(const int &x){return s[fa[x]][0]==x||s[fa[x]][1]==x;}
inline void rev(const int &x){Swap(s[x][0],s[x][1]);tg[x]^=1;}
inline void update(const int &x){xr[x]=xr[s[x][0]]^xr[s[x][1]]^vl[x];}
inline void pushdown(const int &x){if(tg[x])tg[x]=false,rev(s[x][0]),rev(s[x][1]);}
inline void rotate(const int &x)
{
	int y=fa[x],z=fa[y];const bool &k=s[y][1]==x;
	if(isSon(y))s[z][s[z][1]==y]=x;
	int w=s[x][k^1];s[s[x][k^1]=y][k]=w;
	if(w)fa[w]=y;fa[fa[y]=x]=z;update(y);
}
inline void pushall(const int &x){if(isSon(x))pushall(fa[x]);pushdown(x);}
inline void splay(const int x)
{
	pushall(x);const int &y=fa[x];
	while(isSon(x)){if(isSon(y))rotate((s[y][0]==x)^(s[fa[y]][0]==y)?x:y);rotate(x);}update(x);
}
inline void access(int x){for(int y=0;x;x=fa[y=x])splay(x),s[x][1]=y,update(x);}
inline void makeRt(const int &x){access(x);splay(x);rev(x);return;}
inline int fndRt(int x){access(x);splay(x);while(s[x][0])pushdown(x),x=s[x][0];splay(x);return x;}
inline void split(const int &x,const int &y){makeRt(x);access(y);splay(x);}
inline void lnk(const int &x,const int &y){makeRt(x);if(fndRt(y)!=x)fa[x]=y;}
inline void cut(const int &x,const int &y){makeRt(x);if(fndRt(y)==x&&fa[y]==x&&!s[y][0]){fa[y]=s[x][1]=0;update(x);}}
int main()
{
	n=read();int Q=read();rep(1,n,i)vl[i]=read();
	while(Q--)
	{
		int opt=read(),x=read();switch(opt)
		{
			case 0: split(x,read());pt(xr[x]);break;
			case 1: lnk(x,read());break; case 2: cut(x,read());break;
			case 3: splay(x);vl[x]=read();break;
		}
	}
}
